import { useRef } from 'react';
import { motion, useScroll, useTransform } from 'framer-motion';

export default function ScrollCarousel({ items }) {
  const containerRef = useRef(null);
  
  // Track scroll progress through the container
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start end", "end start"]
  });

  // Map scroll progress to a 3D rotation angle
  const rotateY = useTransform(scrollYProgress, [0, 1], [45, -45]);
  const rotateX = useTransform(scrollYProgress, [0, 0.5, 1], [15, 0, -15]);
  const scale = useTransform(scrollYProgress, [0, 0.5, 1], [0.8, 1, 0.8]);

  return (
    <div ref={containerRef} className="relative h-[150vh] flex items-center justify-center perspective-[1200px]">
      <div className="sticky top-0 h-screen w-full flex items-center justify-center overflow-hidden">
        <motion.div
          style={{ rotateY, rotateX, scale, transformStyle: "preserve-3d" }}
          className="flex gap-8 items-center justify-center"
        >
          {items.map((item, i) => (
            <motion.div
              key={i}
              className="w-80 h-96 bg-slate-800/40 border border-slate-700/50 backdrop-blur-xl rounded-2xl p-6 flex flex-col justify-end"
              style={{
                translateZ: Math.abs(i - items.length / 2) * -50,
              }}
            >
              <h3 className="text-xl font-bold text-white mb-2">{item.title}</h3>
              <p className="text-sm text-slate-400">{item.description}</p>
            </motion.div>
          ))}
        </motion.div>
      </div>
    </div>
  );
}
